<form action="/search" method="GET" role="search" style="display: flex; gap: 0.5rem; max-width: 400px;">
    <input type="search" name="q" placeholder="Search articles..." aria-label="Search" required style="flex: 1; padding: 0.5rem 0.75rem; border: 1px solid var(--border); border-radius: 6px; font-family: var(--font); font-size: 0.875rem;">
    <button type="submit" style="background: var(--accent); color: #fff; border: none; padding: 0.5rem 1rem; border-radius: 6px; cursor: pointer; font-size: 0.875rem; font-weight: 600;">Search</button>
</form>
